package at.asitplus.etsi

import at.asitplus.signum.indispensable.io.X509CertificateBase64Serializer
import at.asitplus.testballoon.withData
import de.infix.testBalloon.framework.core.testSuite
import kotlinx.serialization.encodeToString
import kotlinx.serialization.json.Json

val EtsiX509CertificateSerializerTest by testSuite {
    testSuite("deserialization") {
        withData(
            listOf(
                """{"val":""}""",
                """{"val":""}""",
                """{"val":""}""",
                """{"val":""}""",
                """{"val":""}""",
                """{"val":""}""",
                """{"val":""}""",
                """{"val":""}""",
            ).mapIndexed { index, string ->
                "$index: $string" to string
            }.toMap()
        ) {
            Json.decodeFromString(
                EtsiX509CertificateSerializer(),
                it
            )
        }
    }
}